INSERT INTO tbl_insight_result (
     user_id
   , result_type_cd
   , title
   , content
   , use_yn
   , reg_dt
) VALUES (
     #{userId}
   , #{resultTypeCd}
   , #{title}
   , #{content}
   , 'Y'
   , NOW()
)
ON DUPLICATE KEY UPDATE
     title  = VALUES(title)
   , content = VALUES(content)
   , upd_dt  = NOW()
